declare(strict_types=1);

$makeCities = static function (int $provinceId, array $names): array {
    return array_values(array_map(
        static fn (string $name, int $index): array => ['id' => ($provinceId * 100) + $index + 1, 'name' => $name],
        $names,
        array_keys($names)
    ));
};

